// Python codegen for the Ed25519 Done step.
//
// Pedagogical mirror of the in-browser Web Crypto demo: generate a keypair,
// sign a message, verify the signature, then verify a tampered version to
// show the InvalidSignature exception. Uses cryptography.hazmat — the
// canonical production library in Python land.

export function full_script(state) {
  const message = (state && state.ed25_message) || "sign me";
  const messageLiteral = JSON.stringify(message);
  return [
    "# Ed25519 in production — generated by cloak.moosha.org",
    "#",
    "# This is the production equivalent of the in-browser demo: generate",
    "# an Ed25519 keypair, sign a message, verify a fresh signature, and",
    "# watch a tampered signature raise InvalidSignature.",
    "#",
    "# Prerequisites:",
    "#   pip install cryptography",
    "",
    "from cryptography.hazmat.primitives.asymmetric.ed25519 import Ed25519PrivateKey",
    "from cryptography.hazmat.primitives import serialization",
    "from cryptography.exceptions import InvalidSignature",
    "",
    "# Keygen — 32 random bytes hashed to a scalar, then scalar-multiplied by",
    "# the Edwards basepoint to derive the public key. The private key here",
    "# is the raw 32-byte seed; .public_key() recomputes the point on demand.",
    "private_key = Ed25519PrivateKey.generate()",
    "public_key = private_key.public_key()",
    "",
    "# Show the public key in raw form — 32 bytes, exactly what Web Crypto",
    "# exports via exportKey('raw', publicKey).",
    "public_bytes = public_key.public_bytes(",
    "    encoding=serialization.Encoding.Raw,",
    "    format=serialization.PublicFormat.Raw,",
    ")",
    'print("public key (hex):", public_bytes.hex())',
    "",
    `message = ${messageLiteral}.encode("utf-8")`,
    "",
    "# Sign — deterministic (RFC 8032 EdDSA). Same key + same message ⇒",
    "# identical 64-byte signature every time.",
    "signature = private_key.sign(message)",
    'print("signature (hex):", signature.hex())',
    'print("signature length:", len(signature), "bytes")  # always 64',
    "",
    "# Verify a fresh signature — returns None on success, raises on failure.",
    "public_key.verify(signature, message)",
    'print("\\u2713 fresh signature verified")',
    "",
    "# Verify a TAMPERED signature — flip one byte and watch it fail.",
    "tampered = bytearray(signature)",
    "tampered[0] ^= 0x01",
    "try:",
    "    public_key.verify(bytes(tampered), message)",
    '    print("\\u2717 tampered signature accepted — should not happen!")',
    "except InvalidSignature:",
    '    print("\\u2713 tampered signature rejected (InvalidSignature)")',
    "",
    "# Notice: no per-signature nonce input. Ed25519's nonce is derived",
    "# deterministically as r = SHA-512(prefix || message) mod L, which",
    "# eliminates the entire class of nonce-reuse attacks that has bitten",
    "# ECDSA in production (Sony PS3, Bitcoin wallets, Android SecureRandom).",
  ].join("\n");
}

// Info / non-actionable steps emit nothing for the inline code panel.
export function intro(_state) { return ""; }
export function key_derivation(_state) { return ""; }
export function sign_mechanics(_state) { return ""; }
export function verify_mechanics(_state) { return ""; }
export function sign_and_verify(_state) { return ""; }
export function vs_rsa_comparison(_state) { return ""; }
export function done(_state) { return ""; }
